  import sailpoint.object.Application;
  import sailpoint.object.Identity;
  import sailpoint.object.Link;
  import sailpoint.api.IdentityService;
  import sailpoint.api.SailPointContext;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.Filter;
  import sailpoint.object.Attributes;
  import sailpoint.tools.Util;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  private static Log globalADIALogger = LogFactory.getLog("ascension.AD.IdentityAttribute");

  public static Object getGlobalADAttributes(SailPointContext context, Identity identity, String attName){
    Object val = null;
    if(identity == null){
      return val;
    }
    if(attNames == null){
      return val;
    }

    QueryOptions ops = new QueryOptions();
    Filter f = Filter.and(Filter.eq("identity.name",identity.getName()),Filter.eq("primaryAccount","true"),Filter.or(Filter.isnull("psAccount"),Filter.eq("psAccount","false")));
    ops.addFilter(f);
    int size = context.countObjects(Link.class, ops);
    Iterator linksIterator = context.search(Link.class, ops, "attributes");

    int count = 0;

    Object tempVal = null;

    while(linksIterator.hasNext()){
      Object[] linkObject = linksIterator.next();
      Attributes attributes = linkObject[0];
      if(size > 1){
        Object gSuiteStatus = attributes.get("msExchExtensionAttribute40");
        Object attrVal = attributes.get(attName);
        if(null!=attrVal){
          tempVal = attrVal;
        }
        if(null!=gSuiteStatus){
          val = attrVal;
          break;
        }
      } else{
        val = attributes.get(attName);
        break;
      }
    }

    if(val == null){
      val = tempVal;
    }

    if(null!=linksIterator){
      sailpoint.tools.Util.flushIterator(linksIterator);
    }
    return val;
  }

  Object returnVal = null;
  if(null!=identity){
    String type = identity.getType();
    String ministry = identity.getAttribute("ministry");
    String attName = attributeDefinition.getName();

    Application adAmita = context.getObjectByName(Application.class, "AD-AMITA");
    Application adAID = context.getObjectByName(Application.class, "AD-AID");
    IdentityService iService = new IdentityService(context);

    List adLinksAMITA = iService.getLinks(identity, adAmita);
    List adLinksAID = iService.getLinks(identity, adAID);

    if (!adLinksAID.isEmpty()) {

      for (Link link : adLinksAID) {

        if(attName.equalsIgnoreCase("email")){

          if (link.getAttribute("mail") != null && (Util.isNullOrEmpty(link.getAttribute("psAccount")) || Util.nullSafeCaseInsensitiveEq(link.getAttribute("psAccount"),"false"))) {

						return link.getAttribute("mail");

          }

        }

      }

    }

    globalADIALogger.debug("Looking up " + attName + " for " + identity.getName());
    //Switch on the identity attribute, pass in the AD attribute

    if (!adLinksAMITA.isEmpty() && Util.nullSafeCaseInsensitiveEq(ministry, "AMITA Health") && Util.nullSafeCaseInsensitiveEq(type, "non-hr contractor")){
      if (oldValue != null) { //If oldValue is available, utilize it for all Identity Attributes considered by this rule, with the exception of email.
		if (attName.equalsIgnoreCase("telephoneNumber")) {
          for (Link link : adLinksAMITA) {
            if (Util.nullSafeCaseInsensitiveEq(link.getApplication().getName(), "AD-AMITA") && (Util.isNullOrEmpty(link.getAttribute("psAccount")) || Util.nullSafeCaseInsensitiveEq(link.getAttribute("psAccount"),"false"))) {
              String adTelephoneNumber = link.getAttribute("telephoneNumber");

              if (Util.isNotNullOrEmpty(adTelephoneNumber)) {
                return adTelephoneNumber;
              } else {
                Object attrVal = identity.getAttribute(attName);
                if(attrVal == null){
                  return oldValue;
                } else{
                  return attrVal;
                }
              }
            } else {
              Object attrVal = identity.getAttribute(attName);
              if(attrVal == null){
                return oldValue;
              } else{
                return attrVal;
              }
            }
          }
        }
        else {
          Object attrVal = identity.getAttribute(attName);
          if(attrVal == null){
            return oldValue;
          } else{
            return attrVal;
          }
        }
      } else { //If oldValue is NOT available, evaluate a value for email; otherwise, retain a null value for the Identity Attribute considered by this rule.
		if (attName.equalsIgnoreCase("telephoneNumber")) {
          for (Link link : adLinksAMITA) {
            if (Util.nullSafeCaseInsensitiveEq(link.getApplication().getName(), "AD-AMITA") && (Util.isNullOrEmpty(link.getAttribute("psAccount")) || Util.nullSafeCaseInsensitiveEq(link.getAttribute("psAccount"),"false"))) {
              String adTelephoneNumber = link.getAttribute("telephoneNumber");
              if (Util.isNotNullOrEmpty(adTelephoneNumber)) {
                return adTelephoneNumber;
              }
            }
          }
        }
        else {
          Object attrVal = identity.getAttribute(attName);
          return attrVal;
        }
      }
    } else {
      if(attName != null){
        switch(attName){
          case "email": returnVal = getGlobalADAttributes(context, identity, "mail"); break;
          case "firstname": returnVal = getGlobalADAttributes(context, identity, "givenName"); break;
          case "lastname": returnVal = getGlobalADAttributes(context, identity, "sn"); break;
          case "middleName": returnVal = getGlobalADAttributes(context, identity, "initials"); break;
          case "displayName": returnVal = getGlobalADAttributes(context, identity, "displayName"); break;
          case "facsimileTelephoneNumber": returnVal = getGlobalADAttributes(context, identity, "facsimileTelephoneNumber"); break;
          case "city": returnVal = getGlobalADAttributes(context, identity, "city"); break;
          case "mailAlias": returnVal = getGlobalADAttributes(context, identity, "proxyAddresses"); break;
          case "info": returnVal = getGlobalADAttributes(context, identity, "info"); break;
          case "mobile": returnVal = getGlobalADAttributes(context, identity, "mobile"); break;
          case "st": returnVal = getGlobalADAttributes(context, identity, "st"); break;
          case "streetAddress": returnVal = getGlobalADAttributes(context, identity, "streetAddress"); break;
          case "telephoneNumber": returnVal = getGlobalADAttributes(context, identity, "telephoneNumber"); break;
          case "otherTelephone": returnVal = getGlobalADAttributes(context, identity, "otherTelephone"); break;
          case "pager": returnVal = getGlobalADAttributes(context, identity, "pager"); break;
          case "postalCode": returnVal = getGlobalADAttributes(context, identity, "postalCode"); break;
          case "postOfficeBox": returnVal = getGlobalADAttributes(context, identity, "postOfficeBox"); break;
          case "department": returnVal = getGlobalADAttributes(context, identity, "department"); break;
          case "title": returnVal = getGlobalADAttributes(context, identity, "title"); break;
          case "homePhone": returnVal = getGlobalADAttributes(context, identity, "homePhone"); break;
          case "gsuiteStatus": returnVal = getGlobalADAttributes(context, identity, "msExchExtensionAttribute40"); break;
		  case "gsuiteOverrideOU": returnVal = getGlobalADAttributes(context, identity, "msExchExtensionAttribute41"); break;
          case "gsuiteMdm": returnVal = getGlobalADAttributes(context, identity, "msExchExtensionAttribute20"); break;
          case "buildingId": returnVal = getGlobalADAttributes(context, identity, "msExchExtensionAttribute25"); break;
          case "locationDescription": returnVal = getGlobalADAttributes(context, identity, "physicalDeliveryOfficeName"); break;
          case "businessUnit": returnVal = getGlobalADAttributes(context, identity, "extensionAttribute11"); break;
          case "workLocationCode": returnVal = getGlobalADAttributes(context, identity, "extensionAttribute13"); break;
          case "departmentNumber": returnVal = getGlobalADAttributes(context, identity, "extensionAttribute10"); break;
          case "archiving": returnVal = getGlobalADAttributes(context, identity, "extensionAttribute5"); break;
          case "mailDomain": returnVal = getGlobalADAttributes(context, identity, "extensionAttribute9"); break;
          case "managerLevel": returnVal = getGlobalADAttributes(context, identity, "extensionAttribute15"); break;
          case "taniumData": returnVal = getGlobalADAttributes(context, identity, "msExchExtensionAttribute39"); break;
          case "company": returnVal = getGlobalADAttributes(context, identity, "company"); break;
          case "gsuiteLastName": returnVal = getGlobalADAttributes(context, identity, "ASC_GSuite_LastName"); break;
        }
      }
    }
  }
  globalADIALogger.debug("Found " + returnVal);
  return returnVal;
